import xml.etree.ElementTree as ET

def parse_xml(file):
    settings = {}

    tree = ET.parse(file)
    root = tree.getroot()

    for elem in root:
        if len(elem) > 0:
            key = elem.tag
            value = elem.text
            settings[key] = value

    return settings